#!/usr/bin/env node
/**
 * Manual test script for mittwald_cronjob_execution_get tool
 *
 * This script demonstrates testing the tool with sample inputs
 */

import Anthropic from '@anthropic-ai/sdk';

const MCP_SERVER_URL = process.env.MCP_SERVER_URL || 'https://mittwald-mcp-fly2.fly.dev/mcp';

async function testCronjobExecutionGet() {
  console.log('Testing mittwald_cronjob_execution_get tool...\n');

  // Step 1: First, we need to list cronjobs to get valid IDs
  console.log('Step 1: Getting list of cronjobs...');

  try {
    const client = new Anthropic({
      apiKey: process.env.ANTHROPIC_API_KEY,
    });

    // First, let's try to get a list of projects to find a project ID
    console.log('\nAttempting to list projects to find a valid project context...');

    const projectListMessage = await client.messages.create({
      model: 'claude-3-5-sonnet-20241022',
      max_tokens: 4096,
      messages: [{
        role: 'user',
        content: 'Use the mittwald_project_list tool to list all projects. Return the project IDs in your response.'
      }],
      tools: [{
        type: 'custom',
        name: 'mcp__mittwald__mittwald_project_list',
        description: 'List all projects',
        input_schema: {
          type: 'object',
          properties: {},
        }
      }]
    });

    console.log('\nProject list response:');
    console.log(JSON.stringify(projectListMessage, null, 2));

    // Now try to list cronjobs for a project
    console.log('\n\nStep 2: Attempting to list cronjobs...');

    const cronjobListMessage = await client.messages.create({
      model: 'claude-3-5-sonnet-20241022',
      max_tokens: 4096,
      messages: [{
        role: 'user',
        content: 'Use the mittwald_cronjob_list tool to list all cronjobs. Return the cronjob IDs in your response.'
      }],
      tools: [{
        type: 'custom',
        name: 'mcp__mittwald__mittwald_cronjob_list',
        description: 'List cronjobs',
        input_schema: {
          type: 'object',
          properties: {},
        }
      }]
    });

    console.log('\nCronjob list response:');
    console.log(JSON.stringify(cronjobListMessage, null, 2));

  } catch (error) {
    console.error('Error during test:', error);
    if (error instanceof Error) {
      console.error('Error message:', error.message);
      console.error('Error stack:', error.stack);
    }
  }
}

// Run the test
testCronjobExecutionGet().catch(console.error);

