#!/usr/bin/env node
/**
 * Manual test script for mittwald_project_membership_get tool
 *
 * This script tests the tool with both valid and invalid parameters
 */

import Anthropic from '@anthropic-ai/sdk';

const MCP_SERVER_URL = process.env.MCP_SERVER_URL || 'https://mittwald-mcp-fly2.fly.dev/mcp';

async function testProjectMembershipGet() {
  console.log('Testing mittwald_project_membership_get tool...\n');

  const client = new Anthropic({
    apiKey: process.env.ANTHROPIC_API_KEY,
  });

  // Test 1: Get a valid membership ID first by listing memberships
  console.log('Test 1: Getting valid membership ID...');
  try {
    const membershipListMessage = await client.messages.create({
      model: 'claude-3-5-sonnet-20241022',
      max_tokens: 4096,
      messages: [{
        role: 'user',
        content: 'Use the mittwald_project_membership_list_own tool to list all my project memberships. Return ONLY the first membership ID from the response in the format: MEMBERSHIP_ID=<id>'
      }],
      tools: [{
        type: 'custom',
        name: 'mcp__mittwald__mittwald_project_membership_list_own',
        description: 'List own project memberships',
        input_schema: {
          type: 'object',
          properties: {},
        }
      }]
    });

    console.log('Membership list response:');
    console.log(JSON.stringify(membershipListMessage, null, 2));
    console.log('\n---\n');

    // Extract membership ID from response
    let membershipId: string | null = null;
    for (const block of membershipListMessage.content) {
      if (block.type === 'text' && block.text.includes('MEMBERSHIP_ID=')) {
        const match = block.text.match(/MEMBERSHIP_ID=([a-f0-9-]+)/);
        if (match) {
          membershipId = match[1];
          break;
        }
      }
    }

    if (!membershipId) {
      console.log('No membership ID found in response. Will use fallback ID for testing.');
      membershipId = 'pm-test-invalid';
    } else {
      console.log(`Found membership ID: ${membershipId}\n`);
    }

    // Test 2: Call membership get with valid membership ID
    console.log(`Test 2: Calling mittwald_project_membership_get with membershipId="${membershipId}"...`);
    const validTestMessage = await client.messages.create({
      model: 'claude-3-5-sonnet-20241022',
      max_tokens: 4096,
      messages: [{
        role: 'user',
        content: `Use the mittwald_project_membership_get tool with membershipId="${membershipId}". Return the complete response with all membership details.`
      }],
      tools: [{
        type: 'custom',
        name: 'mcp__mittwald__mittwald_project_membership_get',
        description: 'Get project membership details',
        input_schema: {
          type: 'object',
          properties: {
            membershipId: {
              type: 'string',
              description: 'ID of the membership to get details for'
            },
            output: {
              type: 'string',
              enum: ['txt', 'json', 'yaml'],
              description: 'Output format (txt, json, yaml)'
            }
          },
          required: ['membershipId']
        }
      }]
    });

    console.log('Valid membership ID response:');
    console.log(JSON.stringify(validTestMessage, null, 2));
    console.log('\n---\n');

  } catch (error) {
    console.error('Error during valid parameter test:', error);
    if (error instanceof Error) {
      console.error('Error message:', error.message);
    }
  }

  // Test 3: Call with invalid membership ID
  console.log('Test 3: Calling mittwald_project_membership_get with invalid membershipId...');
  try {
    const invalidTestMessage = await client.messages.create({
      model: 'claude-3-5-sonnet-20241022',
      max_tokens: 4096,
      messages: [{
        role: 'user',
        content: 'Use the mittwald_project_membership_get tool with membershipId="pm-invalid-12345". Return the complete response including any errors.'
      }],
      tools: [{
        type: 'custom',
        name: 'mcp__mittwald__mittwald_project_membership_get',
        description: 'Get project membership details',
        input_schema: {
          type: 'object',
          properties: {
            membershipId: {
              type: 'string',
              description: 'ID of the membership to get details for'
            },
            output: {
              type: 'string',
              enum: ['txt', 'json', 'yaml'],
              description: 'Output format (txt, json, yaml)'
            }
          },
          required: ['membershipId']
        }
      }]
    });

    console.log('Invalid membership ID response:');
    console.log(JSON.stringify(invalidTestMessage, null, 2));
    console.log('\n---\n');

  } catch (error) {
    console.error('Error during invalid parameter test:', error);
    if (error instanceof Error) {
      console.error('Error message:', error.message);
    }
  }

  // Test 4: Call without required membershipId parameter
  console.log('Test 4: Calling mittwald_project_membership_get without membershipId...');
  try {
    const missingParamMessage = await client.messages.create({
      model: 'claude-3-5-sonnet-20241022',
      max_tokens: 4096,
      messages: [{
        role: 'user',
        content: 'Try to use the mittwald_project_membership_get tool without providing the membershipId parameter. Report what happens.'
      }],
      tools: [{
        type: 'custom',
        name: 'mcp__mittwald__mittwald_project_membership_get',
        description: 'Get project membership details',
        input_schema: {
          type: 'object',
          properties: {
            membershipId: {
              type: 'string',
              description: 'ID of the membership to get details for'
            },
            output: {
              type: 'string',
              enum: ['txt', 'json', 'yaml'],
              description: 'Output format (txt, json, yaml)'
            }
          },
          required: ['membershipId']
        }
      }]
    });

    console.log('Missing parameter response:');
    console.log(JSON.stringify(missingParamMessage, null, 2));
    console.log('\n---\n');

  } catch (error) {
    console.error('Error during missing parameter test:', error);
    if (error instanceof Error) {
      console.error('Error message:', error.message);
    }
  }

  // Test 5: Call with JSON output format
  console.log('Test 5: Calling mittwald_project_membership_get with JSON output format...');
  try {
    const jsonFormatMessage = await client.messages.create({
      model: 'claude-3-5-sonnet-20241022',
      max_tokens: 4096,
      messages: [{
        role: 'user',
        content: 'Use the mittwald_project_membership_list_own tool to get a membership ID, then use mittwald_project_membership_get with that ID and output format "json". Return the complete response.'
      }],
      tools: [
        {
          type: 'custom',
