          type: 'custom',
          name: 'mcp__mittwald__mittwald_project_membership_get',
          description: 'Get project membership details',
          input_schema: {
            type: 'object',
            properties: {
              membershipId: {
                type: 'string',
                description: 'ID of the membership to get details for'
              },
              output: {
                type: 'string',
                enum: ['txt', 'json', 'yaml'],
                description: 'Output format (txt, json, yaml)'
              }
            },
            required: ['membershipId']
          }
        }
      ]
    });

    console.log('JSON format response:');
    console.log(JSON.stringify(jsonFormatMessage, null, 2));
    console.log('\n---\n');

  } catch (error) {
    console.error('Error during JSON format test:', error);
    if (error instanceof Error) {
      console.error('Error message:', error.message);
    }
  }

  console.log('\nAll tests completed!');
}

// Run the test
testProjectMembershipGet().catch(console.error);

